import{_ as a,a as t,b as n,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Redundante back-up en wisselen van leesbron","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/redundant-backup-and-read-source.md","filePath":"nl-NL/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),o={name:"nl-NL/Other/redundant-backup-and-read-source.md"};function b(p,e,k,u,c,h){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="redundante-back-up-en-wisselen-van-leesbron" tabindex="-1">Redundante back-up en wisselen van leesbron <a class="header-anchor" href="#redundante-back-up-en-wisselen-van-leesbron" aria-label="Permalink to &quot;Redundante back-up en wisselen van leesbron&quot;">​</a></h1><p>Redundante back-up bewaart een extra kopie van een al geüpload bestand.</p><p>Zowel het primaire bestand als het back-upbestand kunnen als leesbron worden gebruikt. Bezoekers merken normaal geen verschil. Het enige verschil is welk opslagkanaal het bestand levert.</p><h2 id="wat-redundante-back-up-kan-doen" tabindex="-1">Wat redundante back-up kan doen <a class="header-anchor" href="#wat-redundante-back-up-kan-doen" aria-label="Permalink to &quot;Wat redundante back-up kan doen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Functie</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Extra kopie bewaren</td><td>Maakt een back-up naar een ander uploadkanaal om het risico van uitval van één kanaal te verkleinen.</td></tr><tr><td>Leesbron wisselen</td><td>Na een geslaagde back-up kun je lezen wisselen tussen primair kanaal en back-upkanaal.</td></tr><tr><td>Back-up per bestand</td><td>Maak een back-up van één bestand vanaf de detailpagina.</td></tr><tr><td>Back-up in batch</td><td>Selecteer meerdere bestanden in het beheer en maak tegelijk een back-up.</td></tr><tr><td>Globale redundante back-up</td><td>Maak back-ups per map vanuit Andere instellingen.</td></tr></tbody></table><h2 id="ingang-voor-redundante-back-up" tabindex="-1">Ingang voor redundante back-up <a class="header-anchor" href="#ingang-voor-redundante-back-up" aria-label="Permalink to &quot;Ingang voor redundante back-up&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+a+'" alt="Redundante back-up" loading="lazy"></p><p>Deze ingang is vooral handig om back-ups toe te voegen aan een map of aan alle bestanden in bulk.</p><p>Het back-upkanaal kan handmatig worden gekozen, of je kiest automatische selectie en laat ImgBed een geschikt back-upkanaal zoeken.</p><h2 id="back-up-vanuit-bestandsdetails" tabindex="-1">Back-up vanuit bestandsdetails <a class="header-anchor" href="#back-up-vanuit-bestandsdetails" aria-label="Permalink to &quot;Back-up vanuit bestandsdetails&quot;">​</a></h2><p>Open de detailpagina van een bestand in het beheer en klik op back-up.</p><p><img src="'+t+'" alt="Back-up in bestandsdetails" loading="lazy"></p><p>Dit is handig voor één belangrijk bestand dat je direct wilt beveiligen.</p><p>Na een geslaagde back-up toont de detailpagina beschikbare leesbronnen.</p><h2 id="batchback-up-via-selectie" tabindex="-1">Batchback-up via selectie <a class="header-anchor" href="#batchback-up-via-selectie" aria-label="Permalink to &quot;Batchback-up via selectie&quot;">​</a></h2><p>Selecteer meerdere bestanden in het beheer en voer batchback-up uit.</p><p><img src="'+n+'" alt="Batchback-up" loading="lazy"></p><p>Dit is geschikt voor een groep bestanden.</p><p>Back-up via selectie, back-up vanuit bestandsdetails en redundante back-up onder Andere instellingen gebruiken hetzelfde back-upsysteem. Het zijn alleen verschillende ingangen.</p><h2 id="leesbron-wisselen-na-back-up" tabindex="-1">Leesbron wisselen na back-up <a class="header-anchor" href="#leesbron-wisselen-na-back-up" aria-label="Permalink to &quot;Leesbron wisselen na back-up&quot;">​</a></h2><p>Na afronding van de back-up kun je op de detailpagina de leesbron wisselen:</p><table tabindex="0"><thead><tr><th>Leesbron</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Primair kanaal</td><td>Leest vanaf het oorspronkelijke uploadkanaal.</td></tr><tr><td>Back-upkanaal</td><td>Leest vanaf het kanaal waar de redundante kopie staat.</td></tr></tbody></table><p><img src="'+r+'" alt="Leesbron wisselen na back-up" loading="lazy"></p><p>Bezoekers hoeven niet te weten of een bestand vanuit het primaire kanaal of het back-upkanaal komt.</p><p>De leesbron die je kiest, wordt de voorkeursbron voor latere bestandstoegang.</p><h2 id="wanneer-back-up-wordt-overgeslagen" tabindex="-1">Wanneer back-up wordt overgeslagen <a class="header-anchor" href="#wanneer-back-up-wordt-overgeslagen" aria-label="Permalink to &quot;Wanneer back-up wordt overgeslagen&quot;">​</a></h2><p>Deze situaties worden tijdens back-up overgeslagen. Het zijn geen fouten.</p><table tabindex="0"><thead><tr><th>Situatie</th><th>Waarom overgeslagen</th></tr></thead><tbody><tr><td>Al geback-upt</td><td>Een bestand dat al een back-up heeft, wordt niet opnieuw geback-upt.</td></tr><tr><td>Primair en back-upkanaal zijn hetzelfde</td><td>Een back-up moet op een ander kanaal staan om zinvol te zijn.</td></tr><tr><td>Geen bruikbaar back-upkanaal</td><td>Er is geen geschikt alternatief kanaal beschikbaar.</td></tr></tbody></table><p>Kort gezegd: back-ups moeten naar een ander kanaal, en al geback-upte bestanden verbruiken niet opnieuw extra ruimte.</p><h2 id="primair-kanaal-en-back-upkanaal" tabindex="-1">Primair kanaal en back-upkanaal <a class="header-anchor" href="#primair-kanaal-en-back-upkanaal" aria-label="Permalink to &quot;Primair kanaal en back-upkanaal&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Naam</th><th>Betekenis</th></tr></thead><tbody><tr><td>Primair kanaal</td><td>Het kanaal dat werd gebruikt toen het bestand voor het eerst werd geüpload.</td></tr><tr><td>Back-upkanaal</td><td>Het kanaal waarin de redundante kopie staat.</td></tr><tr><td>Primaire leesbron</td><td>Het bestand wordt momenteel gelezen vanaf het primaire kanaal.</td></tr><tr><td>Back-up leesbron</td><td>Het bestand wordt momenteel gelezen vanaf het back-upkanaal.</td></tr></tbody></table><p>Primaire en back-up leesbronnen gedragen zich voor gebruikers hetzelfde.</p><p>Zolang het back-upbestand beschikbaar is, blijven afbeeldingen, video&#39;s en downloadlinks werken nadat je naar de back-up leesbron wisselt.</p><h2 id="wat-gebeurt-er-wanneer-een-bestand-wordt-verwijderd" tabindex="-1">Wat gebeurt er wanneer een bestand wordt verwijderd <a class="header-anchor" href="#wat-gebeurt-er-wanneer-een-bestand-wordt-verwijderd" aria-label="Permalink to &quot;Wat gebeurt er wanneer een bestand wordt verwijderd&quot;">​</a></h2><p>Wanneer een bestand wordt verwijderd, verwijdert ImgBed zowel het primaire bestand als het back-upbestand.</p>',37)])])}const w=d(o,[["render",b]]);export{m as __pageData,w as default};
